using System;
using System.Diagnostics;
using TextAnalysis;

const int WarmupIterations = 100;
const int BenchmarkIterations = 100_000;

const string SampleText =
    "The quick brown fox jumps over the lazy dog. " +
    "A quick movement of the enemy will jeopardize six gunboats. " +
    "Pack my box with five dozen liquor jugs. " +
    "How vexingly quick daft zebras jump. " +
    "The five boxing wizards jump quickly. " +
    "Bright vixens jump; dozy fowl quack. " +
    "Sphinx of black quartz judge my vow. " +
    "Two driven jocks help fax my big quiz. " +
    "The jay pig fox dwelt on a kumquat branch. " +
    "Crazy Frederick bought many very exquisite opal jewels.";

var analyzer = new TextAnalyzer(SampleText);

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Iterations: {BenchmarkIterations:N0}");
Console.WriteLine();

// Warmup
for (int i = 0; i < WarmupIterations; i++)
{
    analyzer.AverageWordLength();
    analyzer.WordLengthHistogram();
    analyzer.UniqueWordCount();
}

// Benchmark AverageWordLength
var sw = Stopwatch.StartNew();
for (int i = 0; i < BenchmarkIterations; i++)
    analyzer.AverageWordLength();
sw.Stop();
Console.WriteLine($"AverageWordLength:   {sw.Elapsed.TotalMilliseconds / BenchmarkIterations * 1_000_000:F2} ns/op  (total: {sw.ElapsedMilliseconds} ms)");

// Benchmark WordLengthHistogram
sw.Restart();
for (int i = 0; i < BenchmarkIterations; i++)
    analyzer.WordLengthHistogram();
sw.Stop();
Console.WriteLine($"WordLengthHistogram: {sw.Elapsed.TotalMilliseconds / BenchmarkIterations * 1_000_000:F2} ns/op  (total: {sw.ElapsedMilliseconds} ms)");

// Benchmark UniqueWordCount
sw.Restart();
for (int i = 0; i < BenchmarkIterations; i++)
    analyzer.UniqueWordCount();
sw.Stop();
Console.WriteLine($"UniqueWordCount:     {sw.Elapsed.TotalMilliseconds / BenchmarkIterations * 1_000_000:F2} ns/op  (total: {sw.ElapsedMilliseconds} ms)");

